export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i++
      continue
    }
    if (arg.includes('=')) {
      const [key, value] = arg.split('=', 2)
      result[key] = value
      i++
      continue
    }
    result[arg.slice(2)] = true
    i++
    // Check if next arg is a value (not a flag)
    if (i < argv.length && !argv[i].startsWith('--')) {
      result[arg.slice(2)] = argv[i]
      i++
    }
  }
  return result
}

